     3→export type Expr =
     4→  | { kind: "number"; value: number }
     5→  | { kind: "string"; value: string }
     6→  | { kind: "bool"; value: boolean }
     7→  | { kind: "null" }
     8→  | { kind: "ident"; name: string }
     9→  | { kind: "binary"; op: string; left: Expr; right: Expr }
    10→  | { kind: "unary"; op: string; expr: Expr }
    11→  | { kind: "call"; callee: Expr; args: Expr[] }
    12→  | { kind: "index"; object: Expr; index: Expr }
    13→  | { kind: "member"; object: Expr; property: string }
    14→  | { kind: "assign"; target: Expr; value: Expr }
    15→  | { kind: "array"; elements: Expr[] }
    16→  | { kind: "object"; entries: { key: string; value: Expr }[] }
    17→  | { kind: "fn"; name: string | null; params: string[]; body: Stmt[] }
    18→  | { kind: "ternary"; cond: Expr; then: Expr; else: Expr }
    19→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] }
    20→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    21→
    22→export type MatchArm = { pattern: Expr | null; guard: Expr | null; body: Stmt[] };
    23→
    24→// Phase 6: Capability 타입
    25→export type CapabilityKind =
    26→  | "read_file"
    27→  | "write_file"
    28→  | "network"
    29→  | "spawn_process"
    30→  | "execute_code"
    31→
    32→export type CapabilityAnnotation =
    33→  | { kind: "allow"; cap: CapabilityKind; arg?: string }
    34→  | { kind: "limit"; resource: "cpu" | "memory" | "io"; value: number }
    35→
    36→export type Stmt =
    37→  | { kind: "expr"; expr: Expr }
    38→  | { kind: "let"; name: string; mutable: boolean; init: Expr | null }
    39→  | { kind: "return"; value: Expr | null }
    40→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] | null }
    41→  | { kind: "if-let"; pattern: Expr; value: Expr; body: Stmt[]; else?: Stmt[] }
    42→  | { kind: "while"; cond: Expr; body: Stmt[] }
    43→  | { kind: "while-let"; pattern: Expr; value: Expr; body: Stmt[] }
    44→  | { kind: "for"; name: string; iter: Expr; body: Stmt[] }
    45→  | { kind: "block"; body: Stmt[] }
    46→  | { kind: "break" }
    47→  | { kind: "continue" }
    48→  | { kind: "fn"; name: string; params: string[]; body: Stmt[]; annotations?: CapabilityAnnotation[] }
    49→  | { kind: "print"; expr: Expr; newline: boolean }
    50→  | { kind: "try"; body: Stmt[]; catchVar: string | null; catchBody: Stmt[]; finallyBody: Stmt[] }
    51→  | { kind: "throw"; expr: Expr }
    52→  | { kind: "struct"; name: string; fields: Array<{ name: string; type: string }> }
    53→  | { kind: "import"; names: string[] | null; path: string; alias: string | null }
    54→  | { kind: "export"; stmt: Stmt }
    55→  | { kind: "multi"; stmts: Stmt[] }
    56→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    57→
    58→export type Program = { stmts: Stmt[] };
