     1→// FreeLang v6: Bytecode Compiler
     2→
     3→import { Expr, Stmt, Program, MatchArm } from "./ast";
     4→
     5→export enum Op {
     6→  Const, Pop, Dup,
     7→  Add, Sub, Mul, Div, Mod, Neg,
     8→  Eq, Neq, Lt, Gt, Lte, Gte,
     9→  And, Or, Not,
    10→  Jump, JumpIfFalse, JumpIfTrue,
    11→  Load, Store, LoadGlobal, StoreGlobal,
    12→  Call, Return, Builtin,
    13→  NewArray, Index, SetIndex,
    14→  NewObject, GetProp, SetProp,
    15→  NewClosure, LoadFree, StoreFree,
    16→  Print, Println,
    17→  TryBegin, TryEnd, Throw,
    18→  Iter, IterNext, IterDone,
    19→  AddrOf, Deref,  // v5.9.1: Pointer operators
    20→  // Phase 4: Unsafe 격리 레이어
    21→  Malloc, Free, Realloc,
    22→  UnsafeRead, UnsafeWrite,
    23→  UnsafeBegin, UnsafeEnd,
    24→  Halt,
    25→  // Phase 5.5: Typed Arithmetic Op (런타임 타입 체크 제거)
    26→  AddNum, SubNum, MulNum, DivNum, ModNum,  // Typed arithmetic
    27→  AddStr,                                   // String concatenation (typed)
    28→  EqNum, LtNum, GtNum, LteNum, GteNum,     // Typed comparison
    29→}
    30→
    31→export type Value =
    32→  | { tag: "num"; val: number }
    33→  | { tag: "str"; val: string }
    34→  | { tag: "bool"; val: boolean }
    35→  | { tag: "null" }
    36→  | { tag: "array"; val: Value[] }
    37→  | { tag: "object"; val: Map<string, Value> }
    38→  | { tag: "fn"; name: string; arity: number; addr: number; freeVars: Value[] }
    39→  | { tag: "builtin"; name: string }
    40→  | { tag: "iter"; val: Value[]; idx: number }
    41→  | { tag: "ptr"; addr: number; target?: Value }; // Pointer type (v5.9.1) - STEP 1: target is optional for HeapManager
    42→
    43→export type Chunk = {
    44→  code: number[];
    45→  constants: Value[];
    46→  lines: number[];
    47→};
    48→
    49→type Local = { name: string; depth: number };
    50→type Upvalue = { name: string; isLocal: boolean; index: number };
    51→type CompilerScope = {
    52→  locals: Local[];
    53→  depth: number;
    54→  upvalues: Upvalue[];
    55→};
    56→
    57→type LoopInfo = { startAddr: number; breakPatches: number[] };
    58→
    59→// Phase 5.5: typeEnv는 TypeChecker가 생성한 Map<string, Type>
    60→export function compile(program: Program, typeEnv?: Map<string, any>): Chunk {
    61→  const chunk: Chunk = { code: [], constants: [], lines: [] };
    62→  const scopes: CompilerScope[] = [{ locals: [], depth: 0, upvalues: [] }];
    63→  const globals = new Set<string>();
    64→  const loopStack: LoopInfo[] = [];
    65→  const finallyStack: Stmt[][] = [];
    66→  const constCache = new Map<string, number>(); // Phase 5.4: 상수 중복 제거
    67→
    68→  // Phase 5.5: 표현식의 타입 추론 (기본 추론만, 복잡한 식은 UNKNOWN)
