   583→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   584→        compileExpr(e.then);
   585→        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   586→        patchJump(jumpFalse);
   587→        compileExpr(e.else);
   588→        patchJump(jumpEnd);
   589→        break;
   590→      }
   591→      case "if": {
   592→        // If-expression: if cond { then_block } else { else_block }
   593→        // Both blocks must produce a value on the stack (don't pop last expr)
   594→        compileExpr(e.cond);
   595→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   596→        compileStmtsAsExpr(e.then);
   597→        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   598→        patchJump(jumpFalse);
   599→        compileStmtsAsExpr(e.else);
   600→        patchJump(jumpEnd);
   601→        break;
   602→      }
   603→      case "match": {
   604→        // Match expression: evaluate subject and match against patterns
   605→        compileExpr(e.subject);
   606→        const tempName = `__match_${currentPos()}`;
   607→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   608→
   609→        const endPatches: number[] = [];
   610→        for (const arm of e.arms) {
   611→          if (arm.pattern !== null) {
   612→            // Load subject for comparison
   613→            emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   614→
   615→            // Compile pattern and compare
   616→            compileExpr(arm.pattern);
   617→            emit(Op.Eq);
   618→
   619→            // If guard exists, add it to the condition with AND
   620→            if (arm.guard) {
   621→              compileExpr(arm.guard);
   622→              emit(Op.And);
   623→            }
   624→
   625→            const skip = currentPos();
   626→            emitArg(Op.JumpIfFalse, 0);
   627→
   628→            // Compile body as expression (preserve last value)
   629→            compileStmtsAsExpr(arm.body);
   630→
   631→            endPatches.push(currentPos());
   632→            emitArg(Op.Jump, 0);
   633→            patchJump(skip);
   634→          } else {
   635→            // Wildcard/default arm - always matches
   636→            if (arm.guard) {
   637→              // Even wildcard can have guard
   638→              compileExpr(arm.guard);
   639→              const skip = currentPos();
   640→              emitArg(Op.JumpIfFalse, 0);
   641→              compileStmtsAsExpr(arm.body);
   642→              endPatches.push(currentPos());
   643→              emitArg(Op.Jump, 0);
   644→              patchJump(skip);
   645→            } else {
   646→              // Default case - execute unconditionally
   647→              compileStmtsAsExpr(arm.body);
   648→            }
   649→          }
   650→        }
   651→
   652→        // Patch all end jumps
   653→        const end = currentPos();
   654→        for (const p of endPatches) patchJump(p);
   655→        break;
   656→      }
   657→    }
   658→  }
   659→
   660→  compileStmts(program.stmts);
   661→  emit(Op.Halt);
   662→  return chunk;
   663→}
