   452→              `Max iterations (${this.MAX_SAFE_ITERATIONS}) exceeded.`
   453→            );
   454→          }
   455→
   456→          if (this.traceMode) {
   457→            const indent = "  ".repeat(this.loopDepth);
   458→            this.traceLogs.push(
   459→              `${indent}[JUMP] PC: ${this.ip} → ${targetAddr} (loop-back, offset: ${offset}) | ` +
   460→              `Iteration: ${loopContext.iterationCount}/${this.MAX_SAFE_ITERATIONS}`
   461→            );
   462→          }
   463→        }
   464→
   465→        this.ip = targetAddr;
   466→        break;
   467→      }
   468→      case Op.JumpIfFalse: {
   469→        const addr = this.chunk.code[this.ip++];
   470→        const cond = this.pop();
   471→        const indent = "  ".repeat(this.loopDepth);
   472→
   473→        if (!this.truthy(cond)) {
   474→          // Loop condition FALSE = exit loop
   475→          if (this.loopStack.length > 0) {
   476→            const loopContext = this.loopStack[this.loopStack.length - 1];
   477→
   478→            // Phase 3.8: Compare final state with entry snapshot
   479→            const finalSnapshot = this.captureSnapshot();
   480→            const comparison = this.compareSnapshots(
   481→              {
   482→                stackHeight: loopContext.stackHeightAtEntry,
   483→                globals: loopContext.globalSnapshotAtEntry,
   484→                locals: loopContext.localSnapshotAtEntry,
   485→              },
   486→              {
   487→                stackHeight: finalSnapshot.stackHeight,
   488→                globals: finalSnapshot.globals,
   489→                locals: finalSnapshot.locals,
   490→              }
   491→            );
   492→
   493→            if (this.traceMode) {
   494→              this.traceLogs.push(
   495→                `${indent}[JUMPIF] PC: ${this.ip-1} → ${addr} (condition FALSE, exit loop) | ` +
   496→                `Final iteration count: ${loopContext.iterationCount}`
   497→              );
   498→              this.traceLogs.push(
   499→                `${indent}  └─ Stack balanced: ${comparison.stackBalanced} | ` +
   500→                `Global changes: ${comparison.globalChanges.length} | ` +
   501→                `Local corruption: ${comparison.localChanges}`
   502→              );
   503→              for (const [varName, before, after] of comparison.globalChanges) {
   504→                this.traceLogs.push(
   505→                  `${indent}     ├─ ${varName}: ${this.stringify(before)} → ${this.stringify(after)}`
   506→                );
   507→              }
   508→            }
   509→
   510→            // Store state changes for later analysis
   511→            loopContext.stateChanges = comparison.globalChanges.map(([name, before, after]) => ({
   512→              varName: name,
   513→              before,
   514→              after,
   515→            }));
   516→
   517→            this.loopStack.pop();
   518→            this.loopDepth--;
   519→            if (this.traceMode) {
   520→              this.traceLogs.push(`${indent}  └─ Loop depth: ${this.loopDepth}`);
   521→            }
   522→          }
   523→          this.ip = addr;
   524→        } else {
   525→          // Loop condition TRUE = continue looping
   526→          if (this.traceMode) {
   527→            this.traceLogs.push(`${indent}[JUMPIF] PC: ${this.ip-1} (condition TRUE, continue loop)`);
   528→          }
   529→        }
   530→        break;
   531→      }
   532→      case Op.JumpIfTrue: { const addr = this.chunk.code[this.ip++]; if (this.truthy(this.pop())) this.ip = addr; break; }
   533→
   534→      // Variables
   535→      case Op.Load: {
   536→        const slot = this.chunk.code[this.ip++];
   537→        const value = this.stack[this.baseSlot() + slot];
   538→        // STEP 4: 지역 변수를 Heap 기반으로 로드
   539→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(value)));
   540→        break;
   541→      }
   542→      case Op.Store: {
   543→        const slot = this.chunk.code[this.ip++];
   544→        const value = this.peek();
   545→        // STEP 4: 지역 변수를 Heap에 할당하여 저장
   546→        this.stack[this.baseSlot() + slot] = this.heapPtrToValue(this.valueToHeapPtr(value));
   547→        break;
   548→      }
   549→      case Op.LoadGlobal: {
   550→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   551→        const val = this.globals.get(name.val);
   552→        if (val === undefined) this.runtimeError(`Undefined variable '${name.val}'`);
   553→        // STEP 2: HeapManager 통합 - 글로벌 변수는 heap 기반으로 관리됨
   554→        // PHASE 3 수정: 포인터면 역참조하여 실제 값으로 반환
   555→        // 단, iterator는 상태 유지가 필요하므로 포인터 역참조 대상에서 제외
   556→        this.stack.push(val!.tag === "ptr" ? this.heapPtrToValue(val!) : val!);
   557→        break;
   558→      }
   559→      case Op.StoreGlobal: {
   560→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   561→        const value = this.pop();
   562→        // STEP 2: HeapManager 통합 - 글로벌 변수를 heap에 할당
   563→        // PHASE 3 수정: 포인터를 globals에 직접 저장하여 GC root로 추적 가능하게
   564→        // 단, iterator는 상태 변화가 필요하므로 포인터로 변환하지 않음
   565→        if (value.tag === "iter") {
   566→          this.globals.set(name.val, value);
   567→        } else {
   568→          const heapPtr = this.valueToHeapPtr(value);
   569→          this.globals.set(name.val, heapPtr);
   570→        }
   571→        break;
   572→      }
   573→
   574→      // Functions
   575→      case Op.Call: {
   576→        const argc = this.chunk.code[this.ip++];
   577→        const callee = this.stack[this.stack.length - 1 - argc];
   578→        if (callee.tag === "fn") {
   579→          this.frames.push({ retAddr: this.ip, baseSlot: this.stack.length - argc, fn: callee.name, upvalues: callee.freeVars });
