   586→        } else {
   587→          this.runtimeError(`Cannot call ${callee.tag}`);
   588→        }
   589→        break;
   590→      }
   591→      case Op.Return: {
   592→        const result = this.pop();
   593→        const frame = this.frames.pop()!;
   594→        this.stack.length = frame.baseSlot - 1; // remove locals + callee
   595→        this.stack.push(result);
   596→        this.ip = frame.retAddr;
