   598→        // Safety: clear loop stack when returning from function
   599→        // (loops should not escape function boundaries)
   600→        if (this.frames.length === 0 && this.loopStack.length > 0) {
   601→          this.loopStack = [];
   602→          this.loopDepth = 0;
   603→        }
   604→        break;
   605→      }
   606→
   607→      // Array
   608→      case Op.NewArray: {
   609→        const len = this.chunk.code[this.ip++];
   610→        const elements = this.stack.splice(this.stack.length - len, len);
