   612→        const heapElements = elements.map(el =>
   613→          this.heapPtrToValue(this.valueToHeapPtr(el))
   614→        );
   615→        const arrayValue: Value = { tag: "array", val: heapElements };
   616→        // STEP 5: 배열 자체도 Heap 할당
   617→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(arrayValue)));
