   626→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(element)));
   627→        } else if (obj.tag === "object" && idx.tag === "str") {
   628→          const prop = obj.val.get(idx.val) ?? { tag: "null" };
   629→          // STEP 5: 객체 속성도 Heap 기반으로
   630→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(prop)));
