   632→          const ch = obj.val[Math.floor(idx.val)];
   633→          const result: Value = ch ? { tag: "str", val: ch } : { tag: "null" };
   634→          // STEP 5: 문자열 요소도 Heap 기반으로
   635→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
