   653→        break;
   654→      }
   655→
   656→      // Object
   657→      case Op.NewObject: {
   658→        const count = this.chunk.code[this.ip++];
   659→        const map = new Map<string, Value>();
   660→        const items = this.stack.splice(this.stack.length - count * 2, count * 2);
