   670→        break;
   671→      }
   672→      case Op.GetProp: {
   673→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   674→        const obj = this.pop();
   675→        if (obj.tag === "object") {
   676→          const prop = obj.val.get(name.val) ?? { tag: "null" };
   677→          // STEP 5: 속성값도 Heap 기반으로
   678→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(prop)));
