   684→          const lengthVal = num(obj.val.length);
   685→          // STEP 5: length 속성도 Heap 기반으로
   686→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(lengthVal)));
   687→        } else {
   688→          this.stack.push({ tag: "null" });
   689→        }
   690→        break;
   691→      }
   692→      case Op.SetProp: {
   693→        const propName = this.pop();
   694→        const obj = this.pop();
   695→        const val = this.peek();
   696→        if (obj.tag === "object" && propName.tag === "str") {
