   713→      }
   714→      case Op.LoadFree: {
   715→        const idx = this.chunk.code[this.ip++];
   716→        const frame = this.frames[this.frames.length - 1];
   717→        this.stack.push(frame.upvalues[idx]);
   718→        break;
   719→      }
   720→      case Op.StoreFree: {
   721→        const idx = this.chunk.code[this.ip++];
   722→        const frame = this.frames[this.frames.length - 1];
   723→        frame.upvalues[idx] = this.peek();
   724→        break;
   725→      }
   726→
   727→      // Print
   728→      case Op.Print: this.output.push(this.stringify(this.pop())); break;
   729→      case Op.Println: this.output.push(this.stringify(this.pop()) + "\n"); break;
