   731→      // Try/Catch
   732→      case Op.TryBegin: {
   733→        const catchAddr = this.chunk.code[this.ip++];
   734→        this.tryStack.push({ catchAddr, stackDepth: this.stack.length, frameDepth: this.frames.length });
