   789→          }
   790→        } else {
   791→          this.runtimeError(`Cannot dereference non-pointer type ${ptr.tag}`);
   792→        }
   793→        break;
   794→      }
   795→
   796→      // Phase 4: Unsafe 격리 레이어
   797→      case Op.UnsafeBegin: {
   798→        this.unsafeDepth++;
