   832→        this.stack.push({ tag: "num", val: zoneId });
   833→        break;
   834→      }
   835→
   836→      case Op.Free: {
   837→        if (this.currentUnsafeZone < 0) {
   838→          this.runtimeError("free outside unsafe block");
   839→        }
   840→        const ptrVal = this.pop();
   841→        if (ptrVal.tag !== "num") {
   842→          this.runtimeError("free requires pointer");
   843→        }
   844→        const zoneId = Math.floor(ptrVal.val);
   845→        if (!this.unsafeManager.free(zoneId)) {
   846→          this.runtimeError(`free: invalid zone ID ${zoneId}`);
   847→        }
   848→        break;
   849→      }
   850→
   851→      case Op.Realloc: {
   852→        if (this.currentUnsafeZone < 0) {
   853→          this.runtimeError("realloc outside unsafe block");
   854→        }
   855→        const newSizeVal = this.pop();
   856→        const ptrVal = this.pop();
   857→
   858→        if (newSizeVal.tag !== "num") {
   859→          this.runtimeError("realloc size must be number");
   860→        }
   861→        if (ptrVal.tag !== "num") {
   862→          this.runtimeError("realloc requires pointer");
   863→        }
   864→
   865→        const zoneId = Math.floor(ptrVal.val);
   866→        const newSize = Math.floor(newSizeVal.val);
   867→        const result = this.unsafeManager.realloc(zoneId, newSize);
   868→
   869→        if (!result.success) {
   870→          this.runtimeError(`realloc failed: ${result.reason}`);
   871→        }
   872→
   873→        this.stack.push({ tag: "num", val: result.newZoneId || zoneId });
   874→        break;
   875→      }
   876→
   877→      case Op.UnsafeRead: {
   878→        if (this.currentUnsafeZone < 0) {
   879→          this.runtimeError("Memory access outside unsafe block");
   880→        }
   881→        const offsetVal = this.pop();
   882→        const ptrVal = this.pop();
   883→
   884→        if (offsetVal.tag !== "num") {
   885→          this.runtimeError("offset must be number");
   886→        }
   887→        if (ptrVal.tag !== "num") {
   888→          this.runtimeError("read requires pointer");
   889→        }
   890→
   891→        const zoneId = Math.floor(ptrVal.val);
   892→        const offset = Math.floor(offsetVal.val);
   893→
   894→        if (this.unsafeManager.detectOverflow(zoneId, offset, 1)) {
   895→          this.runtimeError(
   896→            `Buffer overflow: zone=${zoneId}, offset=${offset}`
   897→          );
   898→        }
   899→
   900→        const value = this.unsafeManager.readByte(zoneId, offset);
   901→        if (value === null) {
   902→          this.runtimeError("UnsafeRead failed");
   903→        }
   904→
   905→        this.stack.push({ tag: "num", val: value });
   906→        break;
   907→      }
   908→
   909→      case Op.UnsafeWrite: {
   910→        if (this.currentUnsafeZone < 0) {
   911→          this.runtimeError("Memory access outside unsafe block");
   912→        }
   913→        const valueVal = this.pop();
   914→        const offsetVal = this.pop();
   915→        const ptrVal = this.pop();
   916→
   917→        if (valueVal.tag !== "num") {
   918→          this.runtimeError("value must be number");
   919→        }
   920→        if (offsetVal.tag !== "num") {
   921→          this.runtimeError("offset must be number");
   922→        }
   923→        if (ptrVal.tag !== "num") {
   924→          this.runtimeError("write requires pointer");
   925→        }
   926→
   927→        const zoneId = Math.floor(ptrVal.val);
   928→        const offset = Math.floor(offsetVal.val);
   929→        const value = Math.floor(valueVal.val);
   930→
   931→        if (this.unsafeManager.detectOverflow(zoneId, offset, 1)) {
   932→          this.runtimeError(
   933→            `Buffer overflow: zone=${zoneId}, offset=${offset}`
   934→          );
   935→        }
   936→
   937→        if (!this.unsafeManager.writeByte(zoneId, offset, value)) {
   938→          this.runtimeError("UnsafeWrite failed");
   939→        }
   940→
   941→        this.stack.push({ tag: "num", val: value });
   942→        break;
   943→      }
   944→
   945→      default: this.runtimeError(`Unknown opcode ${op}`);
   946→    }
   947→  }
   948→
   949→  private peek(): Value { return this.stack[this.stack.length - 1]; }
   950→  private pop(): Value { return this.stack.pop()!; }
   951→  private baseSlot(): number { return this.frames.length > 0 ? this.frames[this.frames.length - 1].baseSlot : 0; }
   952→
   953→  // Phase 3.8: Memory snapshot for state integrity
   954→  private captureSnapshot(): { stackHeight: number; globals: Map<string, Value>; locals: Value[] } {
   955→    const stackHeight = this.stack.length;
   956→    const globals = new Map(this.globals);
   957→    const locals = this.stack.slice(0, this.baseSlot()).map(v => ({ ...v })); // shallow copy
   958→    return { stackHeight, globals, locals };
   959→  }
   960→
   961→  private compareSnapshots(
   962→    before: { stackHeight: number; globals: Map<string, Value>; locals: Value[] },
   963→    after: { stackHeight: number; globals: Map<string, Value>; locals: Value[] }
   964→  ): { stackBalanced: boolean; globalChanges: [string, Value, Value][]; localChanges: boolean } {
   965→    const stackBalanced = before.stackHeight === after.stackHeight;
   966→
   967→    // Find global changes
   968→    const globalChanges: [string, Value, Value][] = [];
   969→    for (const [key, beforeVal] of before.globals) {
   970→      const afterVal = after.globals.get(key);
   971→      if (!this.valEq(beforeVal, afterVal || { tag: "null" })) {
   972→        globalChanges.push([key, beforeVal, afterVal || { tag: "null" }]);
   973→      }
   974→    }
   975→    for (const [key] of after.globals) {
   976→      if (!before.globals.has(key)) {
   977→        globalChanges.push([key, { tag: "null" }, after.globals.get(key)!]);
   978→      }
   979→    }
   980→
   981→    // Check if locals changed (shouldn't in safe code)
   982→    const localChanges = before.locals.length !== after.locals.length ||
   983→      before.locals.some((v, i) => !this.valEq(v, after.locals[i] || { tag: "null" }));
   984→
   985→    return { stackBalanced, globalChanges, localChanges };
   986→  }
