   994→  private add(a: Value, b: Value): Value {
   995→    if (a.tag === "num" && b.tag === "num") return num(a.val + b.val);
   996→    if (a.tag === "str" || b.tag === "str") return { tag: "str", val: this.stringify(a) + this.stringify(b) };
   997→    if (a.tag === "array" && b.tag === "array") return { tag: "array", val: [...a.val, ...b.val] };
