  1001→  private valEq(a: Value, b: Value): boolean {
  1002→    if (a.tag !== b.tag) return false;
  1003→    if (a.tag === "null") return true;
  1004→    if (a.tag === "num" || a.tag === "str" || a.tag === "bool") return (a as any).val === (b as any).val;
