  1031→  /**
  1032→   * STEP 1: Value를 HeapObject로 변환하고 ptr 반환
  1033→   * 호환성 유지: ptr도 Value로 래핑 { tag: "ptr", val: <id> }
  1034→   */
  1035→  private valueToHeapPtr(value: Value): Value {
  1036→    // Value의 tag를 TypeID로 매핑
  1037→    let typeId: number;
  1038→    let payload: any;
  1039→
  1040→    switch (value.tag) {
  1041→      case "num":
  1042→        typeId = TYPE_ID.NUM;
  1043→        payload = value.val;
  1044→        break;
  1045→      case "str":
  1046→        typeId = TYPE_ID.STR;
  1047→        payload = value.val;
  1048→        break;
  1049→      case "bool":
  1050→        typeId = TYPE_ID.BOOL;
  1051→        payload = value.val;
  1052→        break;
  1053→      case "null":
  1054→        typeId = TYPE_ID.NULL;
  1055→        payload = null;
  1056→        break;
  1057→      case "array":
  1058→        typeId = TYPE_ID.ARRAY;
  1059→        payload = value.val;
  1060→        break;
  1061→      case "object":
  1062→        typeId = TYPE_ID.OBJECT;
  1063→        payload = value.val;
  1064→        break;
  1065→      case "fn":
  1066→        typeId = TYPE_ID.FN;
  1067→        payload = value;
  1068→        break;
  1069→      case "builtin":
  1070→        typeId = TYPE_ID.BUILTIN;
  1071→        payload = value.name;
  1072→        break;
  1073→      case "iter":
  1074→        typeId = TYPE_ID.ITER;
  1075→        payload = value.val;
  1076→        break;
