  1089→  /**
  1090→   * STEP 1: Ptr Value에서 실제 값으로 역참조
  1091→   */
  1092→  private heapPtrToValue(ptrValue: Value): Value {
  1093→    if (ptrValue.tag !== "ptr") {
  1094→      // 이미 실제 값이면 그대로 반환
  1095→      return ptrValue;
  1096→    }
  1097→
  1098→    const ptr = ptrValue.addr;
  1099→    const heapObj = this.heapManager.get(ptr);
  1100→    if (!heapObj) {
  1101→      this.runtimeError(`Invalid pointer: ${ptr}`);
  1102→    }
  1103→
  1104→    // HeapObject를 Value로 변환
  1105→    const typeId = heapObj!.typeId;
  1106→    const payload = heapObj!.payload;
  1107→
  1108→    switch (typeId) {
  1109→      case TYPE_ID.NUM:
  1110→        return { tag: "num", val: payload };
  1111→      case TYPE_ID.STR:
  1112→        return { tag: "str", val: payload };
  1113→      case TYPE_ID.BOOL:
  1114→        return { tag: "bool", val: payload };
  1115→      case TYPE_ID.NULL:
  1116→        return { tag: "null" };
  1117→      case TYPE_ID.ARRAY:
  1118→        return { tag: "array", val: payload };
  1119→      case TYPE_ID.OBJECT:
  1120→        return { tag: "object", val: payload };
  1121→      case TYPE_ID.FN:
  1122→        return payload as Value; // 이미 fn 형식
  1123→      case TYPE_ID.BUILTIN:
  1124→        return { tag: "builtin", name: payload };
  1125→      case TYPE_ID.ITER:
  1126→        return { tag: "iter", val: payload, idx: 0 };
  1127→      default:
  1128→        this.runtimeError(`Unknown heap type: ${typeId}`);
  1129→    }
  1130→  }
  1131→
  1132→  private runtimeError(msg: string): never {
  1133→    const err: Value = { tag: "str", val: msg };
  1134→    if (this.tryStack.length > 0) {
  1135→      this.handleError(err);
  1136→      // Throw sentinel that run() loop will catch and handle
  1137→      throw new Error("__FREELANG_ERROR_CAUGHT__");
  1138→    }
  1139→    throw new Error(`Runtime Error: ${msg}`);
  1140→  }
  1141→
  1142→  /**
  1143→   * STEP 1: HeapManager 접근 (테스트용)
  1144→   */
  1145→  public getHeapManager(): HeapManager {
  1146→    return this.heapManager;
  1147→  }
