// capabilityCovers: caller 권한이 callee 권한을 포함하는지
private capabilityCovers(caller: Capability, callee: Capability): boolean {
  if (caller.cap !== callee.cap) return false
  if (!callee.arg) return true        // callee가 경로 무관하면 OK
  if (!caller.arg) return false       // caller에 경로 없으면 거부
  if (caller.cap === "read_file" || caller.cap === "write_file")
    return this.pathIsUnder(callee.arg, caller.arg)    // 경로 포함 검사
  if (caller.cap === "network")
    return this.hostMatches(callee.arg, caller.arg)    // 호스트 패턴 매칭
  return caller.arg === callee.arg
}

// pathIsUnder: ".." 즉시 거부, 경로 prefix 검사
private pathIsUnder(target: string, allowedPrefix: string): boolean {
  if (target.includes("..")) return false
  // normalized prefix matching
}

// hostMatches: 와일드카드 *.domain.com 패턴 지원
private hostMatches(target: string, pattern: string): boolean {
  if (pattern === target) return true
  if (pattern.startsWith("*.")) { ... }
}
