#### C. vm.ts — Op.Call 수정: capabilities Frame에 전달

```typescript
case Op.Call: {
  const argc = this.chunk.code[this.ip++];
  const callee = this.stack[this.stack.length - 1 - argc];
  if (callee.tag === "fn") {
    this.frames.push({
      retAddr: this.ip,
      baseSlot: this.stack.length - argc,
      fn: callee.name,
      upvalues: callee.freeVars,
      capabilities: callee.capabilities || []   // <-- 추가
    });
    this.ip = callee.addr;
  } else if (callee.tag === "builtin") {
    // 현재 프레임의 capabilities 검사 후 실행
    this.checkBuiltinCapability(callee.name);  // <-- 추가
    // ...
  }
}
